"use client";

import { useEffect, useState } from "react";
import { Button } from "@/app/ui/button";
import { PaperAirplaneIcon, XMarkIcon } from "@heroicons/react/24/outline";
import { MessageFeature } from "@prisma/client";
//we didn't export from there, how are we importing? because it's a type generated by prisma based on our database schema, and it's available globally in our project. When we run prisma generate, it creates TypeScript types for our database models, and we can import those types directly from the generated Prisma client. In this case, MessageFeature is likely an enum or type defined in our Prisma schema, and
// we can use it in our TypeScript code by importing it from "@prisma/client". that's where it's exported from, even though we didn't explicitly export it ourselves.
import { sendChatMessageWithFeatures } from "@/app/lib/actions";

// TODO : make questions for repo n contributor separate.
type RepoAction = MessageFeature;

type ChatMessage = {
  role: "user" | "assistant";
  content: string;
  features?: RepoAction[];
};

const REPO_ACTIONS: Array<{ id: RepoAction; label: string }> = [
  { id: "repo_summary", label: "Repository Summary" },
  { id: "contributors_summary", label: "Contributors Summary" },
  { id: "generate_questions", label: "Evaluation Questions" },
  { id: "repo_chat", label: "Ask more about Repository" },
];
// TODO : is it best way to do this? Change to correct actions

export default function ChatSection({
  repoId,
  chatId,
  userId,
  githubUrl,
  repoName,
  initialMessages = [],
  //TODO : remove unused values if not needed
}: {
  repoId?: string;
  chatId?: string;
  userId: string;
  githubUrl?: string; //means may or may not have a github url?
  repoName?: string;
  initialMessages?: ChatMessage[];
}) {
  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  //the type of input is defined outside () why? why not inside use state() along with []?
  // useState(<Array<{ role: string; content: string }>>[]) like this?
  // because we want to explicitly define the type of the state variable, and
  // it can be more readable to separate the type definition from the initial value.
  // but it's also common to define the type inline with the initial value, so it's mostly a matter of style and preference.
  // both ways are valid and will work correctly in TypeScript.
  const [input, setInput] = useState("");
  const [sending, setSending] = useState(false);
  const [selectedActions, setSelectedActions] = useState<RepoAction[]>([]);

  const isRepoLoaded = !!repoId && !!chatId; //if there's no repoId and chatId,
  // it means the repo is not loaded yet, another ! means they're loaded
  // so we can show the action buttons
  // now that we navigate to chat section only after repo is loaded, is the check needed?
  //yes, say user opens /chat endpoint directly without loading any repo, we should show them
  // TODO : the message/button to load repo first, instead of showing empty chat section. or redirect. that's better. less clicks for user

  // keep UI in sync when user opens a different chat from sidebar
  useEffect(() => {
    setMessages(initialMessages);
  }, [chatId, initialMessages]);

  function handleSelectAction(id: RepoAction) {
    setSelectedActions((prev) =>
      prev.includes(id) ? prev.filter((item) => item !== id) : [...prev, id],
    );
  }

  function getActionLabel(id: RepoAction) {
    return REPO_ACTIONS.find((action) => action.id === id)?.label ?? id;
  } // actions are fixed, why do we use function on client? why not do ssr of actions and pass label directly? because we want to keep the client component simple and not rely on server-side rendering for dynamic data. By defining the actions and their labels in the client component, we can easily manage the state and interactions without needing to fetch or compute anything from the server. This also allows for a more responsive user experience, as the action labels are readily available without any additional server requests. Additionally, if we ever want to make the actions dynamic in the future, having this logic on the client side will make it easier to implement those changes without needing to modify server-side code.

  function buildUserMessage(text: string, actions: RepoAction[]) {
    const actionLabel = actions.map(getActionLabel).join(", ");
    return text ? `[${actionLabel}] ${text}` : `[${actionLabel}]`;
  }

  // TODO : messages need to be stored in db.
  async function handleSend() {
    if (!isRepoLoaded || sending) return;

    const userText = input.trim().toLowerCase();
    const selected = selectedActions.length
      ? selectedActions
      : (["repo_chat"] as RepoAction[]);

    if (
      !userText &&
      selectedActions.length === 1 &&
      selected[0] === "repo_chat"
    )
      return;

    setSending(true);
    setInput("");

    const userMessage = buildUserMessage(userText, selected);
    setMessages((prev) => [
      ...prev,
      { role: "user", content: userMessage, features: selected },
    ]);

    // here we will need to add final features decided.

    try {
      const answer = await sendChatMessageWithFeatures({
        chatId: chatId!,
        repoId: repoId!,
        userText,
        selectedFeatures: selected,
      });
      setMessages((prev) => [...prev, { role: "assistant", content: answer }]);
    } finally {
      setSending(false); // set sending can be used for showing loading state on UI, like disabling buttons and input, and showing spinner if needed.
      // TODO : how to stream answer being generated? we can use web socket or server sent events for that, but it will require more complex implementation both on client and server side. for now we can just show the final answer after it's generated, and maybe add a loading spinner while waiting for the response.
      setSelectedActions([]);
    }
  }

  const isDisabled = !isRepoLoaded;
  const effectiveActions =
    selectedActions.length > 0 ? selectedActions : ["repo_chat"];
  const isRepoChatOnly =
    effectiveActions.length === 1 && effectiveActions[0] === "repo_chat";
  const isSendDisabled =
    isDisabled || sending || (!input.trim() && isRepoChatOnly);

  return (
    <div className="flex h-[calc(100vh-4rem)] min-h-0 flex-col overflow-hidden rounded-lg border border-gray-200 bg-white shadow-sm">
      {/* TODO : don't show user load repo? */}
      {/* Messages */}
      <div
        className="flex-1 min-h-0 space-y-4 overflow-y-auto p-4"
        style={{ minHeight: "300px", maxHeight: "500px" }}
      >
        {messages.length === 0 && (
          <p className="text-center text-sm text-gray-400">
            {isRepoLoaded
              ? "No messages yet. Start a conversation!"
              : "Your chat will appear here once you load a repository."}
            {/* TODO : load a repo? check when that shows*/}
          </p>
        )}
        {messages.map((msg, idx) => {
          const labels =
            msg.role === "user" ? (msg.features ?? []).map(getActionLabel) : [];
          const hasContent = !!msg.content?.trim();

          return (
            // map has element, index arguments
            <div
              key={idx}
              className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[80%] rounded-lg px-4 py-2 ${
                  msg.role === "user"
                    ? "bg-blue-500 text-white"
                    : "bg-gray-100 text-gray-900"
                }`}
              >
                {labels.length>0 && (
                  <div className="mb-2 flex flex-wrap gap-1">
                    {labels.map((label)=>(
                      <span key={label}
                      className={msg.role ==="user" ? "rounded-full bg-blue-600 px-2 py-0.5 test-[10px] font-medium text-white" : "rounded-full bg-gray-200 px-2 py-0.5 test-[10px] font-medium text-white"}>{label}</span>
                    ))}
                  </div>
                )

                }
                {/* TODO : move action request to above actions, and user text keep here but with larger font */}
                {hasContent ? (
                  <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                ) : (
                  labels.length > 0 && (
                    <p className="text-sm opacity-80">Action Request</p>
                  )
                )}{" "}
              </div>
            </div>
          );
        })}
      </div>

      {/* Input */}
      <div className="border-t border-gray-200 p-4 pt-3 pb-1">
        <p className="mb-2 text-xs font-medium text-gray-500 uppercase tracking-wide">
          Repository Actions
        </p>
        <div className="flex flex-wrap gap-2">
          {REPO_ACTIONS.map((action) => (
            <button
              key={action.id}
              onClick={() => handleSelectAction(action.id)}
              disabled={isDisabled || sending}
              className={`rounded-full border px-3 py-1 text-xs font-medium transition-colors
            ${
              selectedActions.includes(action.id)
                ? "border-blue-500 bg-blue-100 text-blue-700"
                : "border-gray-300 bg-white text-gray-600 hover:border-blue-400 hover:text-blue-600"
            }
            disabled:cursor-not-allowed disabled:opacity-40`}
            >
              {action.label}
            </button>
          ))}
        </div>
        <div className="px-4 pb-4 pt-2">
          {selectedActions.length > 0 && (
            <div className="mb-2 flex items-center gap-1">
              {selectedActions.map((id) => (
                <span
                  key={id}
                  className="inline-flex items-center gap-1 rounded-full bg-blue-500 px-3 py-1 text-xs font-medium text-white"
                >
                  {REPO_ACTIONS.find((a) => a.id === id)?.label}
                  {/* TODO : why find? why not get action.label like above? */}
                  <button
                    onClick={() => handleSelectAction(id)}
                    className="m1-1 rounded-full hover:bg-blue-600 p-0.5"
                    aria-label="Remove selected action"
                  >
                    <XMarkIcon className="h-3 w-3" />
                  </button>
                </span>
              ))}
            </div>
          )}
          <div className="flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) =>
                e.key === "Enter" && !isSendDisabled && handleSend()
              }
              placeholder={
                isDisabled
                  ? "Load a repository to start chatting..."
                  : selectedActions.includes("repo_summary")
                    ? "Optional: add notes (or click Send to ingest now)"
                    : selectedActions.includes("generate_questions")
                      ? 'Optional: focus area (e.g. "authentication flow")'
                      : "Ask a question..."
              }
              // chaining ternary operators for placeholder, is it good? is it better to have separate function to get placeholder based on selected actions? it's a bit complex but still readable, and keeps the JSX cleaner. if we put it in a separate function, we would need to pass selectedActions and isDisabled as arguments, which can make it less straightforward. so in this case, I think using chained ternary operators is acceptable for the placeholder text.
              // TODO : load repo should be shown? or we can redirect to url enter page.
              disabled={isDisabled || sending}
              className="flex-1 rounded-md border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-50 disabled:text-gray-400"
            />
            <Button onClick={handleSend} disabled={isSendDisabled}>
              <PaperAirplaneIcon className="h-5 w-5" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}
